-- Dry runs: trees (4) + linkedlist (3)
BEGIN;

DELETE FROM public."PGcode_interactive_dry_runs" WHERE problem_id IN (
  'invert-binary-tree','max-depth-binary-tree','same-tree','subtree-of-another',
  'merge-two-sorted','linked-list-cycle','reorder-list'
);

-- ====================== TREES ======================

-- invert-binary-tree on [4,2,7,1,3,6,9]

-- max-depth-binary-tree on [3,9,20,null,null,15,7]

-- same-tree: p=[1,2,3], q=[1,2,3]

-- subtree-of-another: root=[3,4,5,1,2], subRoot=[4,1,2]

-- ====================== LINKEDLIST ======================

-- merge-two-sorted: list1=[1,2,4], list2=[1,3,4]

-- linked-list-cycle: [3,2,0,-4] with cycle at index 1

-- reorder-list: [1,2,3,4]

COMMIT;

SELECT problem_id, COUNT(*) AS steps FROM public."PGcode_interactive_dry_runs"
WHERE problem_id IN ('invert-binary-tree','max-depth-binary-tree','same-tree','subtree-of-another','merge-two-sorted','linked-list-cycle','reorder-list')
GROUP BY problem_id ORDER BY problem_id;
